Parent controller events example
In this we add subscription on tabChange event which is an event of left_panel_container controller which actsas parent controller for repository_panel



  {
    id: 'repository_panel',
    controller: {
      init: function () {
        this.subscribeParentEvent({
          key: 'tabChange',
          next: () => { console.log('tab change subs') }
        })
        this.parentEventHandlerNext('tabChange', {
          data: 'map_panel'
        )
      }
    }
  }




